import base64, sys
PATH="index.html"; SENTINEL="PL_PRI_INLINEDOC_V1"
EDITS=[
('dmFyIHBkQWRkaW5nPWZhbHNlOw==','dmFyIHBkQWRkaW5nPWZhbHNlOwp2YXIgcGREb2NBZGRpbmc9ZmFsc2U7'),
('aCs9JzxzcGFuIGNsYXNzPSJwZC1hZGRjaGlwIiBvbmNsaWNrPSJwZEFkZERvYygpIj4nK1BEX0FERCsnIEFkZCBkb2N1bWVudDwvc3Bhbj4nOyBkYy5pbm5lckhUTUw9aDsgfQ==',''),
('',''),
('cGRBZGRpbmc9ZmFsc2U7IGN1clBpZD1pZDsgY3VyUHJpPXByaUJ5SWQoaWQpOw==','cGRBZGRpbmc9ZmFsc2U7IHBkRG9jQWRkaW5nPWZhbHNlOyBjdXJQaWQ9aWQ7IGN1clByaT1wcmlCeUlkKGlkKTs=')
]
s=open(PATH,encoding="utf-8").read()
if SENTINEL in s:
    print("Already applied — no change.")
else:
    for k,(ob,nb) in enumerate(EDITS):
        old=base64.b64decode(ob).decode("utf-8"); new=base64.b64decode(nb).decode("utf-8")
        n=s.count(old)
        if n!=1:
            sys.stderr.write("ABORT edit %d: anchor count=%d (expected 1)\n"%(k,n)); sys.exit(1)
        s=s.replace(old,new)
    open(PATH,"w",encoding="utf-8").write(s)
    print("Applied %s. New size: %d bytes."%(SENTINEL,len(s.encode("utf-8"))))
